INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 7, 1, 106001, 0, "キャル", 1, 0, 0.0, 0.0, "たまには\n協力するのもいいんじゃない？\nあたしも手を貸してあげる", 7001, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 7, 1, 105901, 0, "コッコロ", 1, 0, 0.0, 0.0, "多くの方と協力して\n戦えるようです\n主さまなら、さぞ\nご活躍なさることでしょう", 7002, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 7, 1, 105801, 0, "ペコリーヌ", 1, 0, 0.0, 0.0, "たくさんの人と一緒に\n協力バトルです！\nがんばりましょう☆", 7003, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 10, 1, 105801, 0, "ペコリーヌ", 1, 0, 0.0, 0.0, "ジュエルを食べ物…\nいえ、貴重品と交換できます！", 10001, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 10, 1, 106001, 0, "キャル", 1, 0, 0.0, 0.0, "ジュエルはよく考えて\n使うことね\n無駄遣い厳禁！", 10002, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 10, 1, 105901, 0, "コッコロ", 1, 0, 0.0, 0.0, "主さまのジュエルで\n貴重な品々を購入できます\nですが、無駄遣いは\n『めっ』でございますよ", 10003, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 10, 1, 106401, 0, "シェフィ", 2, 2104010, 0.0, 0.0, "ジュエルがあれば\n貴重品と交換できるみたい\n大事に使いましょうね", 10004, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, "2030/12/17 14:59:59", 12, 1, 105801, 0, "ペコリーヌ", 1, 0, 0.0, 0.0, "特定の条件を達成すると\n報酬がもらえますよ！\nがんばりましょう♪　", 12001, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 13, 1, 106001, 0, "キャル", 1, 0, 0.0, 0.0, "思い出が詰まってるって\nいろいろあったけど\n振り返るのもいいんじゃない？", 13001, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 13, 1, 105901, 0, "コッコロ", 1, 0, 0.0, 0.0, "主さまとの楽しい日々…\nこちらで何度でも\n思い返しましょう♪", 13002, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 13, 1, 106401, 0, "シェフィ", 2, 2104010, 0.0, 0.0, "みんなとの大切な思い出が\nたくさん詰まってるのね\n一緒に振り返って、\n心に刻みたいわ", 13003, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 13, 1, 105801, 0, "ペコリーヌ", 1, 0, 0.0, 0.0, "女の子との思い出が\nたくさん見られますよ！\nヒューヒュー♪\nモテモテですねー☆", 13004, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 14, 1, 105901, 0, "コッコロ", 1, 0, 0.0, 0.0, "育成に必要なアイテムが\n獲得できるクエストです\nわたくし、主さまのために、\n強くなりますよ", 14001, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 14, 1, 106401, 0, "シェフィ", 2, 2104010, 0.0, 0.0, "このクエストを攻略すると、\nアイテムが手に入るらしいわ。\nもっと強くなるために、\n一生懸命がんばるわね！", 14002, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 14, 1, 105801, 0, "ペコリーヌ", 1, 0, 0.0, 0.0, "このクエストを攻略すれば、\nアイテムがもらえますよ\nたくさん集めて、どんどん\n強くなっちゃいましょう！", 14003, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 14, 1, 106001, 0, "キャル", 1, 0, 0.0, 0.0, "クエストを攻略すると、\nアイテムが手に入るんだって\nもらえるものは、\nもらっておきましょ！", 14004, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-470.0, "2030/12/17 14:59:59", 15, 1, 105901, 0, "コッコロ", 1, 0, 0.0, 0.0, "主さま、旅の準備を整えて\nより充実した冒険をいたし\nましょう", 15001, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 16, 1, 106401, 0, "シェフィ", 2, 2104010, 0.0, 0.0, "ねぇ…クランに加入してみない？\n一人も楽しいけど、みんなと\n一緒も賑やかでいいと思うの", 16001, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 16, 1, 105801, 0, "ペコリーヌ", 1, 0, 0.0, 0.0, "クランに加入してみませんか？\nみんなといっしょに冒険した方が、\n楽しいですよ！", 16002, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 16, 1, 106001, 0, "キャル", 1, 0, 0.0, 0.0, "クランに入れるらしいわよ\nせっかくだから入ってみたら？\nけっこう楽しいみたいよ♪", 16003, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 16, 1, 105901, 0, "コッコロ", 1, 0, 0.0, 0.0, "こちらでクランに加入できます\n素敵なクランがたくさんあって、\n目移りしてしまいますね", 16004, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 17, 1, 105901, 0, "コッコロ", 1, 0, 0.0, 0.0, " こちらではクランバトルに\n 参加された仲間のみなさんの\n 活躍を振り返ることができます", 17002, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 25, 1, 106001, 0, "キャル", 1, 0, 0.0, 0.0, "模擬戦の戦績もアンタが\n気に入ったものがあれば\n記録しておけるのね", 17004, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 25, 1, 105901, 0, "コッコロ", 1, 0, 0.0, 0.0, "主さま、今回のクランバトルでの\nご活躍が記録されています\nバトルの参考にいたしましょう", 17005, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 25, 1, 106401, 0, "シェフィ", 2, 2104010, 0.0, 0.0, "今回のクランバトルの調子は\nどうかしら？\n戦績を見れば、次のバトルに\n活かせるかもしれないわ", 17006, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 25, 1, 105801, 0, "ペコリーヌ", 1, 0, 0.0, 0.0, "今回のクランバトルでの戦績を\nおさらいできますよ！\n私にも見せてください☆", 17007, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 18, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "ようこそ！\nこちらでは、\nギルドハウスで流れる音楽の\n変更や購入が出来ますよ", 18001, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 18, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "ＢＧＭの変更や購入は、こちらから\nできますよ\n素敵な音楽を、たくさんご用意\nいたしました！", 18002, 2, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-470.0, "2030/12/17 14:59:59", 19, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "ギルドハウスの\nＢＧＭを変更できますよ\nあなたの好きな曲、\n私にも聴かせてくださいね", 19001, 3, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-470.0, "2030/12/17 14:59:59", 19, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "こちらでは、ＢＧＭの変更が\nできますよ\nどんな曲に変更しますか？\nふふふ、私も楽しみです♪", 19002, 4, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-470.0, "2030/12/17 14:59:59", 20, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "こちらでは、ＢＧＭを購入\nすることができますよ\n試聴することもできるので、\nじっくり選んでくださいね", 20001, 5, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-470.0, "2030/12/17 14:59:59", 20, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "いらっしゃいませ！\nＢＧＭの購入はこちらです\n素敵な曲がたくさんあって、\n目移りしちゃいますね", 20002, 6, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 21, 1, 106001, 0, "キャル", 1, 0, 0.0, 0.0, "ここで手に入れたアイテムで\n専用装備を作成できるみたいね\nアイテムが集まったら\nさっそく作ってみましょ！", 21001, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 21, 1, 105901, 0, "コッコロ", 1, 0, 0.0, 0.0, "攻略すると珍しいアイテムが\n手に入りますよ\nこのアイテムで専用装備を\n作成できるようです", 21002, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 21, 1, 106401, 0, "シェフィ", 2, 2104010, 0.0, 0.0, "専用装備が欲しいなら\nこのクエストに挑戦するといいわ\n集めた素材でもっともっと\n強くなりましょう", 21003, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 21, 1, 105801, 0, "ペコリーヌ", 1, 0, 0.0, 0.0, "専用装備の作成に必要な\nアイテムを獲得できますよ\nたくさん集めてどんどん\n強くなりましょう！", 21004, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-430.0, "2030/12/17 14:59:59", 22, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "投票はこちらです\nあなたが応援したい女の子に\n思いを込めた一票を\nお願いします！", 22001, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-430.0, "2030/12/17 14:59:59", 22, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "ようこそ！\nあなたが思いを寄せるのは\nどの女の子ですか？\n応援してあげてくださいね！", 22002, 2, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-430.0, "2030/12/17 14:59:59", 23, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "たくさんの投票、\nありがとうございました\n結果発表を楽しみに\n待っていてくださいね！", 23001, 3, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-430.0, "2030/12/17 14:59:59", 23, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "ただ今、人気投票の\n集計中です\n結果が出るまでもう少しだけ\nお待ちくださいね", 23002, 4, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, "2030/12/17 14:59:59", 24, 2, 109001, 10011, "エリコ（バレンタイン）", 1, 0, 4.08, 8.0, "あなた様が手伝ってくださった\nチョコレートケーキ\n美味しくないはずがありませんわ", 24001, 1, "2019/01/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, "2030/12/17 14:59:59", 24, 2, 109001, 10011, "エリコ（バレンタイン）", 1, 0, 5.0, 8.0, "このような失敗、あなた様が\nするはずありません\nもう一度挑戦してみましょう", 24002, 2, "2019/01/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, "2030/12/17 14:59:59", 24, 2, 109001, 10011, "エリコ（バレンタイン）", 1, 0, 10.11, 8.0, "あなた様のために\n作っているケーキを\nあなた様に手伝っていただく……\nことになるなんて……クスクス", 24003, 3, "2019/01/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, "2030/12/17 14:59:59", 24, 2, 109001, 10011, "エリコ（バレンタイン）", 1, 0, 4.0, 8.0, "あまり気に病む必要はありませんわ\nこれからは私がたっぷりと\n時間をかけて教えて差し上げますから", 24004, 4, "2019/01/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, "2030/12/17 14:59:59", 24, 2, 109001, 10011, "エリコ（バレンタイン）", 1, 0, 6.0, 8.0, "今回は調子が悪かった……のですか？\nあなた様が手伝ってくれたものなら\nわたしはどんなものでも……クスクス", 24005, 5, "2019/01/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, "2030/12/17 14:59:59", 24, 1, 109002, 10011, "エリコ（バレンタイン）", 1, 0, 0.0, 0.0, "あなた様が手がけた\nチョコレートケーキは\n私にとっての宝物……\n侮辱する者は生かしておきませんわ", 24006, 6, "2019/01/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, "2030/12/17 14:59:59", 24, 1, 109002, 10011, "エリコ（バレンタイン）", 1, 0, 0.0, 0.0, "とても素晴らしい出来栄えですわ！\nあなた様にふさわしい\nチョコレートケーキができました", 24007, 7, "2019/01/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, "2030/12/17 14:59:59", 24, 1, 109002, 10011, "エリコ（バレンタイン）", 1, 0, 0.0, 0.0, "私を手伝ってくれたあなた様は\nすでに私の虜……\n甘い世界に誘って差し上げますわ", 24008, 8, "2019/01/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, "2030/12/17 14:59:59", 24, 1, 109002, 10011, "エリコ（バレンタイン）", 1, 0, 0.0, 0.0, "あなた様の愛情\nしかと受け止めました\nこれが……私たちの初めての\n共同作業ですわね……クスクス", 24009, 9, "2019/01/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, "2030/12/17 14:59:59", 24, 1, 109002, 10011, "エリコ（バレンタイン）", 1, 0, 0.0, 0.0, "これは世界一の\nチョコレートケーキですわ\nだって、あなた様が腕によりをかけて\n作ってくださったんですもの", 24010, 10, "2019/01/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, "2030/12/17 14:59:59", 24, 2, 109101, 10011, "シズル（バレンタイン）", 1, 0, 2.12, 8.0, "上手にできなくて残念だった？\nでも、弟くんの気持ちが嬉しいな\nいつだってお姉ちゃんは\nそばにいるからね♪", 24011, 1, "2019/01/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, "2030/12/17 14:59:59", 24, 2, 109101, 10011, "シズル（バレンタイン）", 5, 0, 4.19, 8.0, "うーん、弟くんには珍しく\n緊張しちゃったのかな？\nもう一度チャレンジしてみる？", 24012, 2, "2019/01/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, "2030/12/17 14:59:59", 24, 4, 109101, 10011, "シズル（バレンタイン）", 2, 0, 2.3, 8.0, "お姉ちゃんのお手伝い、\nよくできました！\nあー、\nまだつまみ食いしちゃダメだぞ！", 24013, 3, "2019/01/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, "2030/12/17 14:59:59", 24, 1, 109102, 10011, "シズル（バレンタイン）", 1, 0, 0.0, 0.0, "見てみて！\nスポンジに綺麗な焼き目がついてるよ\nさっすが弟くんだね！", 24014, 4, "2019/01/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, "2030/12/17 14:59:59", 24, 2, 109101, 10011, "シズル（バレンタイン）", 5, 0, 5.23, 8.0, "まぁまぁ、落ち込まないで\n見た目は……個性的だけど、\n味は絶対美味しいはずだから！", 24015, 5, "2019/01/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, "2030/12/17 14:59:59", 24, 1, 109102, 10011, "シズル（バレンタイン）", 1, 0, 0.0, 0.0, "弟くんみたいな\n可愛いケーキができたよ！\n早く食べてみたいでしょ♪", 24016, 6, "2019/01/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, "2030/12/17 14:59:59", 24, 2, 109101, 10011, "シズル（バレンタイン）", 1, 0, 5.01, 8.0, "あれれ？　弟くん、指に\nチョコレートがくっついてるよ？\nお姉ちゃんが舐めてあげるね、\nはぁむ！", 24017, 7, "2019/01/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, "2030/12/17 14:59:59", 24, 1, 109102, 10011, "シズル（バレンタイン）", 1, 0, 0.0, 0.0, "なかなか上手にできたんじゃない？\nでも弟くんはまだまだできる子！\nお姉ちゃん、信じてるからね", 24018, 8, "2019/01/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, "2030/12/17 14:59:59", 24, 1, 109102, 10011, "シズル（バレンタイン）", 1, 0, 0.0, 0.0, "わぁ～、\nとっても美味しそうにできたね！\n弟くん手慣れてたから\nお姉ちゃん安心して任せられちゃった！", 24019, 9, "2019/01/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, "2030/12/17 14:59:59", 24, 1, 109102, 10011, "シズル（バレンタイン）", 1, 0, 0.0, 0.0, "や～ん、弟くんが手伝ってくれた\nチョコレートケーキ！\nすっごく美味しそうにできたね♪", 24020, 10, "2019/01/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 26, 1, 106401, 0, "シェフィ", 2, 2104010, 0.0, 0.0, "ここから先は神聖な場所みたい\nどんなお宝が眠っているのか、\n今から探索するのが楽しみね♪", 26001, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 26, 1, 105801, 0, "ペコリーヌ", 1, 0, 0.0, 0.0, "ここから先は神聖な場所\nみたいです！\nどんなお宝が手に入るか\n楽しみですね！", 26002, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 26, 1, 106001, 0, "キャル", 1, 0, 0.0, 0.0, "この先は神聖な場所みたい。\n手に入るお宝も並じゃないけど\n気を付けていかないと\n痛い目にあうわよ", 26003, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 26, 1, 105901, 0, "コッコロ", 1, 0, 0.0, 0.0, "ここから先は神聖な場所\nでございます。\n気を引き締めてお宝の\n調査探索に参りましょう", 26004, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 27, 1, 106401, 0, "シェフィ", 2, 2104010, 0.0, 0.0, "ここにさらなる力を得るための\nアイテムが眠っている…って\nみんな言ってるわ。ふふっ、\nそれじゃあ挑戦してみましょうか", 27001, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 27, 1, 105801, 0, "ペコリーヌ", 1, 0, 0.0, 0.0, "ここにさらなる力を得るための\nアイテムが眠っているみたい\nです！　どこから挑戦するか\n迷っちゃいますね！", 27002, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 27, 1, 106001, 0, "キャル", 1, 0, 0.0, 0.0, "ここにさらなる力を得るための\nアイテムが眠っているみたい！\nどんどん挑戦して\n強くなっちゃいましょ！", 27003, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 27, 1, 105901, 0, "コッコロ", 1, 0, 0.0, 0.0, "こちらにさらなる力を得る\nためのアイテムが眠っている\nようです。主さま、どこから\n挑戦いたしましょう。", 27004, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 28, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "ようこそ！\n皆さんの素敵な出会いを\nギルド管理協会が\nお手伝いします！", 28001, 1, "2019/09/24 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 28, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "ギルド管理協会です\nフレンドに関しては\nこちらでご確認ください", 28002, 2, "2019/09/24 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2030/12/17 14:59:59", 29, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "こちらがフレンドの\n皆さんです\n素敵な関係を\n築いてくださいね！", 29001, 3, "2019/09/24 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2030/12/17 14:59:59", 29, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "こちらの一覧で\nフレンドのプロフィールを\n確認できますよ", 29002, 4, "2019/09/24 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2030/12/17 14:59:59", 30, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "フレンド管理は\nこちらになります\n新しいフレンドとの出会いを\n楽しんでくださいね！", 30001, 5, "2019/09/24 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2030/12/17 14:59:59", 30, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "フレンドの申請や\n承認ができますよ\nどうぞ、良き交流を！", 30002, 6, "2019/09/24 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2030/12/17 14:59:59", 31, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "バトルをして力比べを\nしてみましょう！\n実力が試されますね、\n頑張ってください！", 31001, 7, "2019/10/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2030/12/17 14:59:59", 31, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "気になるパーティと\nバトルをしてみましょう！\nどちらが勝利するのか、\n私も楽しみにしていますね", 31002, 8, "2019/10/31 12:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2020/01/04 4:59:59", 32, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "ルーキーの皆さんのために\n特別なミッションを\nご用意いたしました！\nぜひ、挑戦してください！", 32001, 1, "2019/12/20 5:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2020/01/04 4:59:59", 32, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", 32002, 2, "2019/12/20 5:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2020/01/04 4:59:59", 33, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "フレンドになって\n初心者の方を応援しましょう！\n素敵な報酬が待っていますよ！", 33001, 3, "2019/12/20 5:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2020/01/04 4:59:59", 33, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", 33002, 4, "2019/12/20 5:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2020/01/10 11:59:59", 34, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "お疲れ様でした！\nミッションの報酬の受け取りは\nこちらからできますよ！", 34001, 5, "2020/01/04 5:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2020/01/10 11:59:59", 34, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "ミッション報酬の受け取りは\nこちら！\n受け取り漏れの無いように\n気を付けてくださいね！", 34002, 6, "2020/01/04 5:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-458.0, "2030/12/17 14:59:59", 38, 2, 105801, 0, "ペコリーヌ", 1, 0, 5.3, 0.0, "過去のストーリーイベントを\n楽しめちゃいますよ！\n遊んだことのないものがあれば\n一緒にやってみましょう♪", 38001, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-458.0, "2030/12/17 14:59:59", 38, 2, 105801, 0, "ペコリーヌ", 1, 0, 6.5, 0.0, "これまでのイベントで登場した\n限定キャラを仲間にできたり\nメモリーピースが手に入る\nみたいですよ。やばいですね☆", 38002, 2, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (9999.0, "2020/04/08 23:59:59", 39, 3, 105801, 0, "ペコリーヌ", 3, 0, 0.0, 9999.0, "", 39005, 0, "2020/04/01");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-430.0, "2030/12/17 14:59:59", 40, 1, 190801, 0, "カリン", 1, 0, 0.0, 0.0, "これまでに出題された\n問題を振り返ることが\nできますよ\n復習は大切です♪", 40001, 2, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 41, 1, 106401, 0, "シェフィ", 1, 2104010, 0.0, 0.0, "ここでは腕試しが\nできるんですって。\n自分の実力を測るのに、\nちょうどよさそうね。", 41001, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 41, 1, 105801, 0, "ペコリーヌ", 1, 0, 0.0, 0.0, "ここで腕試しを\nしていきましょう！\n全力全開、\nがんばっちゃいますよ～！", 41002, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 41, 1, 106001, 0, "キャル", 1, 0, 0.0, 0.0, "ここで腕試しが\nできるみたいね。\n試してみるのも\nいいんじゃない？", 41003, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 41, 1, 105901, 0, "コッコロ", 1, 0, 0.0, 0.0, "腕試しができるようです。\nここで練習を重ね、実戦に\n活かしてまいりましょう。", 41004, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, "2030/12/17 14:59:59", 42, 1, 105901, 0, "コッコロ", 1, 0, 0.0, 0.0, "訓練の成果に応じて、\n報酬がもらえるそうです。\n共に励んでいきましょう。", 42001, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, "2030/12/17 14:59:59", 42, 1, 106401, 0, "シェフィ", 1, 2104010, 0.0, 0.0, "目標を達成すれば、\n報酬がもらえるみたい。\n頑張り甲斐があるわね。", 42002, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, "2030/12/17 14:59:59", 42, 1, 105801, 0, "ペコリーヌ", 1, 0, 0.0, 0.0, "腕試しをがんばれば、\n報酬がもらえますよ。\n挑戦していきましょう☆", 42003, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, "2030/12/17 14:59:59", 42, 1, 106001, 0, "キャル", 1, 0, 0.0, 0.0, "ミッションを達成すると、\n報酬が出るんですって。\n一緒にやってみましょ！", 42004, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 43, 1, 105801, 0, "ペコリーヌ", 1, 0, 0.0, 0.0, "ここからアリーナに\n挑戦できますよ！\n編成を工夫してライバルに\n挑んじゃいましょう！", 43001, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 43, 1, 105901, 0, "コッコロ", 1, 0, 0.0, 0.0, "こちらからアリーナに\n挑戦することができます。\n主さまらしい編成で\nライバルに挑みましょう。", 43002, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", 43, 1, 106001, 0, "キャル", 1, 0, 0.0, 0.0, "ここからアリーナに\n挑戦できるわよ！\nしっかり編成を考えて\nライバルに挑みなさい！", 43003, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, "2030/12/17 14:59:59", 44, 1, 123001, 0, "アメス", 1, 0, 0.0, 0.0, "ミッションをクリアすると報酬が\n受け取れるわ。ジャンジャン\nクリアしてバリバリ強化して\nあげなさい♪", 43004, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, "2030/12/17 14:59:59", 44, 1, 123001, 0, "アメス", 1, 0, 0.0, 0.0, "ぼんやりしてる場合じゃないわ。\n早くミッションをクリアして\n報酬を受け取ってきなさい！", 43005, 2, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, "2030/12/17 14:59:59", 45, 2, 123001, 0, "アメス", 1, 0, 5.79, 0.0, "ちょっとあんた、報酬が\n受け取れるじゃない！\n忘れずにチェックなさい。\nアメス様との約束よ？", 43006, 3, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-371.5, "2030/12/17 14:59:59", 46, 1, 123001, 0, "アメス", 1, 0, 0.0, 0.0, "はい、お疲れさま。\nここではマスタリーチケットを\n使って、マスタリー強化素材を\n手に入れることができるわよ。", 46001, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, "2030/12/17 14:59:59", 47, 2, 104901, 0, "シズル", 2, 0, 0.0, 0.0, "呼ばれて飛び出てお姉ちゃんだよ♪\nたとえ火の中、水の中、迷宮の中っ\nこのダンジョンを踏破できるよう\n弟くんを応援してあげるからねっ♪", 47001, 1, "2015/12/17 15:00:00");
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, "2030/12/17 14:59:59", 47, 2, 101101, 0, "リノ", 1, 0, 9.32, 0.0, "ほんとーに不思議な場所ですね～\nお兄ちゃんが冒険を頑張れるよう\nおまじないをかけてあげますねっ\nフレーフレー、お・兄・ちゃんっ♪", 47002, 1, "2015/12/17 15:00:00");
